import math
from collections import defaultdict

def is_good(s):
    l = len(s)
    for d in range(1, int(math.isqrt(l)) + 1):
        if l % d == 0:
            k = l // d
            if k >= 2:
                # Check if s is made of k copies of a substring of length d
                substr = s[:d]
                if substr * k == s:
                    return False
    return True

def solve(w):
    n = len(w)
    dp = [float('inf')] * (n + 1)
    cnt = [0] * (n + 1)
    dp[0] = 0
    cnt[0] = 1

    for i in range(1, n + 1):
        for j in range(i):
            substr = w[j:i]
            if is_good(substr):
                if dp[j] + 1 < dp[i]:
                    dp[i] = dp[j] + 1
                    cnt[i] = cnt[j]
                elif dp[j] + 1 == dp[i]:
                    cnt[i] = (cnt[i] + cnt[j]) % (10**9 + 7)
    return dp[n], cnt[n]

if __name__ == '__main__':
    w = sys.stdin.read().strip()
    min_parts, num_ways = solve(w)
    print(min_parts)
    print(num_ways % (10**9 + 7))"}

