import math

def expected_rolls(N, M):
    if M >= N:
        return 0.0
    # We need to compute E(m) for m from 0 to N-1
    # Let's create an array where dp[m] is the expected number of rolls needed when we have m consecutive evens
    dp = [0.0] * (N + 1)
    # dp[N] = 0.0
    # We'll compute dp[m] for m from N-1 down to 0
    for m in range(N-1, -1, -1):
        if m == N-1:
            # E(m) = 1 + 0.5 * 0 + 0.5 * E(0)
            dp[m] = 1 + 0.5 * 0 + 0.5 * dp[0]
        else:
            # E(m) = 1 + 0.5 * E(m+1) + 0.5 * E(0)
            dp[m] = 1 + 0.5 * dp[m+1] + 0.5 * dp[0]
    return dp[M]


def main():
    T = int(sys.stdin.readline())
    for _ in range(T):
        N, M = map(int, sys.stdin.readline().split())
        result = expected_rolls(N, M)
        print(f"{result:.2f}")

if __name__ == "__main__":
    main()"}

